const result = $input.first().json;
const webhook = $('Webhook: POST /contract-create').first().json;
const sub = Array.isArray(result) ? result[0] : result;
return [{ json: {
  success: true,
  submission_id: sub.submission_id || sub.id,
  slug: sub.slug || '',
  status: sub.status || 'pending',
  sign_url: sub.slug ? ($vars.DOCUSEAL_BASE_URL || 'https://docuseal.orbiters.co.kr') + '/s/' + sub.slug : '',
  handle: webhook.body.handle,
  name: webhook.body.name,
  email: webhook.body.email,
  payment: webhook.body.payment
} }];

const body = $input.first().json.body || $input.first().json;
const data = body.data || body;
const submitters = data.submitters || [];
const sub = submitters[0] || {};
return [{ json: {
  submission_id: data.submission_id || data.id,
  status: 'completed',
  signer_name: sub.name || '',
  signer_email: sub.email || '',
  completed_at: sub.completed_at || new Date().toISOString(),
  documents: (data.documents || []).map(d => ({ name: d.name, url: d.url }))
} }];

const sub = $input.first().json;
const docs = sub.documents || [];
const pdfDoc = docs.find(d => d.url && d.url.endsWith('.pdf')) || docs[0] || {};
return [{ json: {
  submission_id: sub.id,
  signer_name: (sub.submitters || [{}])[0].name || '',
  signer_email: (sub.submitters || [{}])[0].email || '',
  pdf_url: pdfDoc.url || '',
  completed_at: (sub.submitters || [{}])[0].completed_at || '',
  all_documents: docs
} }];

const result = $input.first().json;
const subs = result.data || result || [];
const pending = subs.filter(s => {
  const submitters = s.submitters || [];
  return submitters.some(sub => sub.status === 'pending' || sub.status === 'sent' || sub.status === 'opened');
});
if (!pending.length) return [{ json: { _noPending: true, total: subs.length } }];
return pending.map(s => ({ json: s }));
